#include<bits/stdc++.h>
using namespace std;
long long sum[3000010],dp[3000010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long min1;
    }a[3000010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].min1=1e18;
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long v)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].min1=v;
            return;
        }
        update(a[x].lson,p,v);
        update(a[x].rson,p,v);
        pushup(x);
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e18;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n,l,a,b;
    scanf("%lld%lld%lld%lld",&n,&l,&a,&b);
    for(long long i=1;i<=n;i++)
    {
        long long s,e;
        scanf("%lld%lld",&s,&e);
        sum[s+1]++;
        sum[e]--;
    }
    for(long long i=1;i<=l;i++)
    {
        sum[i]+=sum[i-1];
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    t.init(0,l);
    t.update(1,0,0);
    for(long long i=a*2;i<=l;i+=2)
    {
        if(sum[i]==0)
        {
            long long L=max(0ll,i-b*2),R=i-a*2;
            dp[i]=t.getmin(1,L,R)+1;
            t.update(1,i,dp[i]);
        }
    }
    if(dp[l]>=1e18)
    {
        printf("-1");
        return 0;
    }
    printf("%lld",dp[l]);
    return 0;
}
